/**
 * Institutional Funder Evidence Workspace — Controlled Pilot (PR #26)
  *
   * Static, execution-free guard over the pilot fixture migration and its
    * readiness RPC. Cannot prove the migration runs against a real database
     * (that requires a disposable Postgres/Supabase instance — see
      * docs/pr-26-validation-package.md) but proves, by inspection, that:
       *   - every fixture uses the fixed synthetic id documented in the PR;
        *   - inserts are applied in a foreign-key-safe order;
         *   - every insert is idempotent (ON CONFLICT ... DO NOTHING) and the one
          *     UPDATE is non-destructive (only fills a NULL pointer);
           *   - the readiness RPC's status vocabulary is exactly
            *     Ready / Missing / Incorrectly linked (never "ok");
             *   - the isolation check reads from the correct tables with fixed ids and
              *     never requires a release to already exist;
               *   - the Pilot Console renders every row the RPC returns and never claims
                *     readiness unless every row reads Ready.
                 */
                 import { describe, it, expect } from "vitest";
                 import { readFileSync } from "node:fs";
                 import { join } from "node:path";

                 const ROOT = process.cwd();
                 const MIGRATION_PATH = "supabase/migrations/20260713090000_pilot_fixture_and_readiness_rpc.sql";
                 const SQL = readFileSync(join(ROOT, MIGRATION_PATH), "utf8");
                 const CONSOLE_BODY = readFileSync(
                   join(ROOT, "src/pages/admin/funder-workspace/PilotConsole.tsx"),
                     "utf8",
                     );
                     const DEAL_DETAIL_BODY = readFileSync(
                       join(ROOT, "src/pages/funder/workspace/DealDetail.tsx"),
                         "utf8",
                         );
                         const NEW_RELEASE_BODY = readFileSync(
                           join(ROOT, "src/pages/admin/funder-workspace/NewRelease.tsx"),
                             "utf8",
                             );

                             const FIXED_IDS: Record<string, string> = {
                               c_funder_bank_id: "00000000-0000-4000-a000-000000000001",
                                 c_funder_isolation_id: "00000000-0000-4000-a000-000000000002",
                                   c_buyer_org_id: "00000000-0000-4000-a000-000000000003",
                                     c_seller_org_id: "00000000-0000-4000-a000-000000000004",
                                       c_match_id: "00000000-0000-4000-a000-000000000005",
                                         c_doc_invoice_id: "00000000-0000-4000-a000-000000000006",
                                           c_doc_bol_id: "00000000-0000-4000-a000-000000000007",
                                             c_kyc_record_id: "00000000-0000-4000-a000-000000000008",
                                               c_evidence_item_id: "00000000-0000-4000-a000-000000000009",
                                                 c_evidence_version_id: "00000000-0000-4000-a000-00000000000a",
                                                   c_evidence_pack_id: "00000000-0000-4000-a000-00000000000b",
                                                   };

                                                   describe("Pilot fixture migration — fixed synthetic ids", () => {
                                                     it("declares every documented fixed id at least once with its exact value", () => {
                                                         for (const [name, value] of Object.entries(FIXED_IDS)) {
                                                               const re = new RegExp(`${name}\\s+uuid\\s*:=\\s*'${value}'`);
                                                                     expect(SQL, `${name} := '${value}'`).toMatch(re);
                                                                         }
                                                                           });

                                                                             it("uses the same fixed ids in both the fixture DO block and the readiness RPC", () => {
                                                                                 const doBlock = SQL.slice(0, SQL.indexOf("END $do$;"));
                                                                                     const rpcBlock = SQL.slice(SQL.indexOf("CREATE OR REPLACE FUNCTION public.fw_admin_check_pilot_fixtures_v1"));
                                                                                         for (const [name, value] of Object.entries(FIXED_IDS)) {
                                                                                               if (name === "c_kyc_record_id") continue; // not referenced by the RPC
                                                                                                     expect(doBlock, `${name} in fixture block`).toContain(value);
                                                                                                           expect(rpcBlock, `${name} in RPC block`).toContain(value);
                                                                                                               }
                                                                                                                 });
                                                                                                                 });
                                                                                                                 
                                                                                                                 describe("Pilot fixture migration — fixture names", () => {
                                                                                                                   it("names every fixture exactly as documented", () => {
                                                                                                                       const expectedNames = [
                                                                                                                             "Pilot Funder Bank",
                                                                                                                                   "Isolation Test Fund",
                                                                                                                                         "DEMO — Acacia Trading Test Pty Ltd",
                                                                                                                                               "DEMO — Blue River Exports Test Pty Ltd",
                                                                                                                                                     "DEMO — Acacia–Blue River Pilot Trade",
                                                                                                                                                           "DEMO pro-forma invoice",
                                                                                                                                                                 "DEMO bill of lading",
                                                                                                                                                                     ];
                                                                                                                                                                         for (const name of expectedNames) {
                                                                                                                                                                               expect(SQL, name).toContain(name);
                                                                                                                                                                                   }
                                                                                                                                                                                     });
                                                                                                                                                                                     
                                                                                                                                                                                       it("does not use unrelated placeholder fixture names", () => {
                                                                                                                                                                                           // Guards against a prior validation draft that referenced fixtures
                                                                                                                                                                                               // never created by this migration.
                                                                                                                                                                                                   for (const wrong of ["Demo Trading Co", "Demo Counterparty Ltd", "Demo Funder\"", "'Demo Funder'"]) {
                                                                                                                                                                                                         expect(SQL, wrong).not.toContain(wrong);
                                                                                                                                                                                                             }
                                                                                                                                                                                                               });
                                                                                                                                                                                                               });
                                                                                                                                                                                                               
                                                                                                                                                                                                               describe("Pilot fixture migration — foreign-key-safe insertion order", () => {
                                                                                                                                                                                                                 it("creates each row only after the rows it references", () => {
                                                                                                                                                                                                                     const idx = (needle: string) => SQL.indexOf(needle);
                                                                                                                                                                                                                         const iFunderOrgs = idx("INSERT INTO public.p5_batch3_funder_organisations");
                                                                                                                                                                                                                             const iOrganizations = idx("INSERT INTO public.organizations");
                                                                                                                                                                                                                                 const iMatch = idx("INSERT INTO public.matches");
                                                                                                                                                                                                                                     const iDocs = idx("INSERT INTO public.match_documents");
                                                                                                                                                                                                                                         const iKyc = idx("INSERT INTO public.p5_batch2_kyc_records");
                                                                                                                                                                                                                                             const iItem = idx("INSERT INTO public.p5_batch2_evidence_items");
                                                                                                                                                                                                                                                 const iVersion = idx("INSERT INTO public.p5_batch2_evidence_versions");
                                                                                                                                                                                                                                                     const iPack = idx("INSERT INTO public.p5_batch2_evidence_packs");
                                                                                                                                                                                                                                                         const iPackItem = idx("INSERT INTO public.p5_batch2_evidence_pack_items");
                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                             for (const i of [iFunderOrgs, iOrganizations, iMatch, iDocs, iKyc, iItem, iVersion, iPack, iPackItem]) {
                                                                                                                                                                                                                                                                   expect(i).toBeGreaterThan(-1);
                                                                                                                                                                                                                                                                       }
                                                                                                                                                                                                                                                                           expect(iFunderOrgs).toBeLessThan(iOrganizations);
                                                                                                                                                                                                                                                                               expect(iOrganizations).toBeLessThan(iMatch);
                                                                                                                                                                                                                                                                                   expect(iMatch).toBeLessThan(iDocs);
                                                                                                                                                                                                                                                                                       expect(iMatch).toBeLessThan(iKyc);
                                                                                                                                                                                                                                                                                           expect(iKyc).toBeLessThan(iItem);
                                                                                                                                                                                                                                                                                               expect(iItem).toBeLessThan(iVersion);
                                                                                                                                                                                                                                                                                                   expect(iVersion).toBeLessThan(iPack);
                                                                                                                                                                                                                                                                                                       expect(iPack).toBeLessThan(iPackItem);
                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                         describe("Pilot fixture migration — idempotency and non-destructiveness", () => {
                                                                                                                                                                                                                                                                                                           it("qualifies every INSERT with ON CONFLICT (id) DO NOTHING", () => {
                                                                                                                                                                                                                                                                                                               const inserts = SQL.match(/INSERT INTO public\.\w+/g) ?? [];
                                                                                                                                                                                                                                                                                                                   expect(inserts.length).toBeGreaterThanOrEqual(9);
                                                                                                                                                                                                                                                                                                                       const onConflicts = SQL.match(/ON CONFLICT \(id\) DO NOTHING/g) ?? [];
                                                                                                                                                                                                                                                                                                                           expect(onConflicts.length).toBe(inserts.length);
                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                               it("has exactly one UPDATE, and it only fills a NULL current_version_id", () => {
                                                                                                                                                                                                                                                                                                                                   const updates = SQL.match(/^\s*UPDATE public\.\w+/gm) ?? [];
                                                                                                                                                                                                                                                                                                                                       expect(updates.length).toBe(1);
                                                                                                                                                                                                                                                                                                                                           expect(SQL).toMatch(/UPDATE public\.p5_batch2_evidence_items\s*\n\s*SET current_version_id = c_evidence_version_id\s*\n\s*WHERE id = c_evidence_item_id\s*\n\s*AND current_version_id IS NULL/);
                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                             describe("Pilot fixture migration — relationship integrity", () => {
                                                                                                                                                                                                                                                                                                                                               it("attaches the demo match to both demo organisations as buyer and seller", () => {
                                                                                                                                                                                                                                                                                                                                                   const matchInsertBlock = SQL.slice(SQL.indexOf("INSERT INTO public.matches"), SQL.indexOf("INSERT INTO public.match_documents"));
                                                                                                                                                                                                                                                                                                                                                       expect(matchInsertBlock).toContain("c_buyer_org_id, c_seller_org_id");
                                                                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                           it("attaches both demo documents to the demo match", () => {
                                                                                                                                                                                                                                                                                                                                                               const docsBlock = SQL.slice(SQL.indexOf("INSERT INTO public.match_documents"), SQL.indexOf("INSERT INTO public.p5_batch2_kyc_records"));
                                                                                                                                                                                                                                                                                                                                                                   const matches = docsBlock.match(/\(c_doc_\w+_id, c_match_id,/g) ?? [];
                                                                                                                                                                                                                                                                                                                                                                       expect(matches.length).toBe(2);
                                                                                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                           it("chains kyc record -> evidence item -> evidence version -> pack item consistently", () => {
                                                                                                                                                                                                                                                                                                                                                                               expect(SQL).toMatch(/\(c_kyc_record_id, 'transaction_party',[\s\S]*?c_match_id,/);
                                                                                                                                                                                                                                                                                                                                                                                   expect(SQL).toMatch(/\(c_evidence_item_id, c_kyc_record_id, 'trade_evidence_pack'/);
                                                                                                                                                                                                                                                                                                                                                                                       expect(SQL).toMatch(/\(c_evidence_version_id, c_evidence_item_id, 1,/);
                                                                                                                                                                                                                                                                                                                                                                                           expect(SQL).toMatch(/\(c_evidence_pack_item_id, c_evidence_pack_id, c_evidence_item_id, c_evidence_version_id,/);
                                                                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                               it("links the eligible evidence pack to the demo match and the seller organisation", () => {
                                                                                                                                                                                                                                                                                                                                                                                                   expect(SQL).toMatch(/\(c_evidence_pack_id, c_seller_org_id, c_match_id,/);
                                                                                                                                                                                                                                                                                                                                                                                                     });
                                                                                                                                                                                                                                                                                                                                                                                                     });
                                                                                                                                                                                                                                                                                                                                                                                                     
                                                                                                                                                                                                                                                                                                                                                                                                     describe("Pilot readiness RPC — status vocabulary and access control", () => {
                                                                                                                                                                                                                                                                                                                                                                                                       it("returns check_key, label, status, detail and only the three approved status literals", () => {
                                                                                                                                                                                                                                                                                                                                                                                                           expect(SQL).toMatch(/RETURNS TABLE\(check_key text, label text, status text, detail text\)/);
                                                                                                                                                                                                                                                                                                                                                                                                               const assigned = SQL.match(/s\d\s*:=\s*'([^']+)'/g) ?? [];
                                                                                                                                                                                                                                                                                                                                                                                                                   expect(assigned.length).toBeGreaterThan(0);
                                                                                                                                                                                                                                                                                                                                                                                                                       for (const a of assigned) {
                                                                                                                                                                                                                                                                                                                                                                                                                             expect(["Ready", "Missing", "Incorrectly linked"].some((v) => a.includes(`'${v}'`))).toBe(true);
                                                                                                                                                                                                                                                                                                                                                                                                                                 }
                                                                                                                                                                                                                                                                                                                                                                                                                                     // Guards against regressing to a different vocabulary (e.g. "ok").
                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(SQL).not.toMatch(/status\s*:=\s*'ok'/);
                                                                                                                                                                                                                                                                                                                                                                                                                                           });
                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                             it("gates the RPC behind platform_admin and restricts execute grants", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                 expect(SQL).toMatch(/IF NOT public\.p5b3_is_platform_admin\(\) THEN\s*\n\s*RAISE EXCEPTION 'fw\.forbidden: platform_admin required';/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(SQL).toMatch(/REVOKE EXECUTE ON FUNCTION public\.fw_admin_check_pilot_fixtures_v1\(\) FROM PUBLIC, anon;/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(SQL).toMatch(/GRANT EXECUTE ON FUNCTION public\.fw_admin_check_pilot_fixtures_v1\(\) TO authenticated, service_role;/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                           });
                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                                             it("returns exactly 9 rows, one per documented check", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                 const valuesBlock = SQL.slice(SQL.indexOf("RETURN QUERY VALUES"), SQL.indexOf("END; $$;"));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                     const rows = valuesBlock.match(/\('\w+',/g) ?? [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(rows.length).toBe(9);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                           });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                           });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                                                           describe("Pilot readiness RPC — isolation check", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                             it("proves isolation from the correct tables using fixed ids, not organizations and not the first arbitrary release", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 const isolationBlock = SQL.slice(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       SQL.indexOf("-- 9. Isolation proof"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             SQL.indexOf("RETURN QUERY VALUES"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(isolationBlock.length).toBeGreaterThan(0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(isolationBlock).toMatch(/FROM public\.funder_deal_releases/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             expect(isolationBlock).toMatch(/match_id = c_match_id/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 expect(isolationBlock).toMatch(/funder_organisation_id = c_funder_isolation_id/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     // Must not resolve the isolation org via the wrong table.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(isolationBlock).not.toMatch(/FROM public\.organizations/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             // Must not infer the demo match from "the first release ever created".
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 expect(isolationBlock).not.toMatch(/order by created_at asc/i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(isolationBlock).not.toMatch(/limit 1/i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         it("is Ready when zero releases exist, and only Missing when a prerequisite fixture is absent", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const isolationBlock = SQL.slice(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   SQL.indexOf("-- 9. Isolation proof"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         SQL.indexOf("RETURN QUERY VALUES"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 expect(isolationBlock).toMatch(/v_isolation_release_count > 0/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(isolationBlock).toMatch(/s9 := 'Ready'/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(isolationBlock).toMatch(/s9 := 'Missing'/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             expect(isolationBlock).toMatch(/s9 := 'Incorrectly linked'/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 // The Ready branch must not be gated on a release already existing.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(isolationBlock).not.toMatch(/funder_deal_releases[\s\S]*RAISE EXCEPTION[\s\S]*not.*found/i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         it("does not require funder_deal_releases for any of the pre-release fixture checks (1-8)", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const preReleaseBlock = SQL.slice(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   SQL.indexOf("-- 1. Pilot Funder Bank"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         SQL.indexOf("-- 9. Isolation proof"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 expect(preReleaseBlock).not.toMatch(/funder_deal_releases/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   describe("Pilot Console — renders every readiness row and role wording", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     it("iterates over every row the RPC returns without slicing or filtering", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         expect(CONSOLE_BODY).toMatch(/checks\.map\(\(c\)\s*=>/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             expect(CONSOLE_BODY).not.toMatch(/checks\.(slice|filter)\([^)]*\)\.map/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 it("only claims all-ready when every returned check is Ready", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(CONSOLE_BODY).toMatch(/checks\.every\(\(c\)\s*=>\s*c\.status === "Ready"\)/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         it("includes a static label for the new isolation check", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             expect(CONSOLE_BODY).toMatch(/isolation_no_release:\s*"Isolation Test Fund/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 it("states the approved RFI / decision role rule verbatim", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     expect(CONSOLE_BODY).toContain(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           "Funder Admin, Reviewer and Approver can create RFIs. Viewer cannot create RFIs. Only Approver can record a formal decision.",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 describe("Deal Detail — stale wording removed", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   it("no longer claims PDF generation is coming in a future build batch", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       expect(DEAL_DETAIL_BODY).not.toMatch(/PDF generation comes in the next build batch/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           it("no longer shows generic 'Not yet connected' evidence-room placeholders", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               expect(DEAL_DETAIL_BODY).not.toMatch(/Not yet connected/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 describe("New Release — no raw evidence-pack UUID/version input; shared consent labels", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   it("never renders a free-text input bound to the evidence pack id or version", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       expect(NEW_RELEASE_BODY).not.toMatch(/<Input[^>]*evidence_pack/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           it("auto-selects the sole eligible evidence pack instead of requiring manual entry", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               expect(NEW_RELEASE_BODY).toMatch(/packs\.length === 1/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   it("imports the shared consent label map instead of a local duplicate", () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       expect(NEW_RELEASE_BODY).toMatch(/import \{ CONSENT_STATUS_LABELS \} from "@\/lib\/funder-workspace\/consent-labels"/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           expect(NEW_RELEASE_BODY).not.toMatch(/const CONSENT_STATUS_LABELS:\s*Record/);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
